const extToFileType = {
  'pdf': 'pdf',
  'docx': 'docx',
  'xlsx': 'xlsx',
  'md': 'md',
  'txt': 'txt'
};

const results = [];
for (const item of $input.all()) {
  const file = item.json;
  const ext = (file.name || '').split('.').pop().toLowerCase();
  const fileType = extToFileType[ext];
  if (!fileType) continue;
  results.push({ json: { ...file, file_type: fileType } });
}

return results;

// Filtra arquivos já ingeridos sem modificação
// Arquivos novos ou com modifiedTime > último ingested_at são processados
const allItems = $input.all();
if (allItems.length === 0) return [];

const token = $('Login Nexus API').first().json.token;

const files = allItems.map(item => ({
  source_url: 'https://drive.google.com/file/d/' + item.json.id + '/view',
  modified_time: item.json.modifiedTime || new Date(0).toISOString()
}));

const response = await fetch('https://api.nexus.ethra.com.br/api/v1/wiki/sources/check-new', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer ' + token
  },
  body: JSON.stringify({ files })
});

if (!response.ok) {
  throw new Error('check-new falhou: ' + response.status + ' ' + await response.text());
}

const { to_process } = await response.json();
const processSet = new Set(to_process.map(f => f.source_url));

return allItems.filter(item => {
  const url = 'https://drive.google.com/file/d/' + item.json.id + '/view';
  return processSet.has(url);
});

// Converte binário (filesystem ou memória) para base64
// e monta o payload para /wiki/ingest
const downloadItems = $input.all();
const filterItems = $('Filtrar recentes e tipo suportado').all();
const results = [];

for (let i = 0; i < downloadItems.length; i++) {
  const item = downloadItems[i];
  const filterItem = filterItems[i]?.json;
  if (!filterItem) continue;

  const binary = item.binary;
  let content_base64 = null;
  const debug = { hasBinary: !!binary, binaryKeys: [], source: null, error: null };

  if (binary) {
    debug.binaryKeys = Object.keys(binary);
    const binaryKey = Object.keys(binary)[0];
    if (binaryKey) {
      const bd = binary[binaryKey];
      debug.mimeType = bd.mimeType;
      debug.fileName = bd.fileName;
      debug.binaryId = bd.id;
      debug.dataLength = (bd.data || '').length;

      if (bd.data && bd.data.length > 0) {
        // Modo memória: data já é base64
        content_base64 = bd.data;
        debug.source = 'memory';
      } else if (bd.id) {
        // Modo filesystem: lê diretamente do disco
        try {
          const fs = require('fs');
          const p = '/home/node/.n8n/binaryData/' + bd.id;
          const buf = fs.readFileSync(p);
          content_base64 = buf.toString('base64');
          debug.source = 'filesystem';
          debug.diskSize = buf.length;
        } catch (e) {
          debug.error = e.message;
        }
      }
    }
  }

  if (!content_base64) {
    throw new Error('Falha ao ler binário de ' + filterItem.name + ': ' + JSON.stringify(debug));
  }

  results.push({
    json: {
      content_base64,
      file_type: filterItem.file_type,
      source_name: filterItem.name,
      source_url: 'https://drive.google.com/file/d/' + filterItem.id + '/view',
      source_origin: 'google_drive'
    }
  });
}

return results;
